import axios from 'axios';

// ─── BASE URL ─────────────────────────────────────────────────────────────────
// Your backend: localhost:3000 (no /api prefix — routes are /Admin/SignIn etc.)
const BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3000';

const api = axios.create({
  baseURL: BASE_URL,
  headers: { 'Content-Type': 'application/json' },
});

// Auto-attach JWT token to every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('fixit_admin_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// If 401 → clear storage and go to login
api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('fixit_admin_token');
      localStorage.removeItem('fixit_admin_user');
      window.location.href = '/login';
    }
    return Promise.reject(err);
  }
);

// ─── YOUR EXACT RESPONSE FORMAT ────────────────────────────────────────────────
// Every response from your backend is: { Status: "OK" | "Fail" | "Conflict", Result: ... }
// We use this helper to check success everywhere in the app
export const isOK = (res) => res?.data?.Status === 'OK';

// ─── ADMIN AUTH ────────────────────────────────────────────────────────────────
// POST /Admin/SignIn         body: { Email, Password }
// Response OK: { Status:"OK", Result:{ Name, Email, ContactNo, Role, _id } }
// Response Fail: { Status:"Fail", Result:"Invalid Email" | "Invalid Password" }
export const adminSignIn = (Email, Password) =>
  api.post('/Admin/SignIn', { Email, Password });

// POST /Admin/SignUp         body: { Name, Email, ContactNo, Role, Status }
// Response OK: { Status:"OK", Result:"Successfully Saved" }
export const adminSignUp = (data) =>
  api.post('/Admin/SignUp', data);

// PUT /Admin/ChangePassword  body: { _id, oldPassword, newPassword }
export const adminChangePassword = (_id, oldPassword, newPassword) =>
  api.put('/Admin/ChangePassword', { _id, oldPassword, newPassword });

// PUT /Admin/ChangeProfile   body: { _id, Name, Email, ContactNo }
export const adminChangeProfile = (_id, Name, Email, ContactNo) =>
  api.put('/Admin/ChangeProfile', { _id, Name, Email, ContactNo });

// POST /Admin/ForgotPassword body: { Email }
// Response OK: { Status:"OK", Result:"New password sent to email" }
export const adminForgotPassword = (Email) =>
  api.post('/Admin/ForgotPassword', { Email });

// GET /Admin/AdminList
// Response OK: { Status:"OK", Result:[ { Name, Email, ContactNo, Role, Status, _id } ] }
export const getAdminList = () =>
  api.get('/Admin/AdminList');

// PUT /Admin/ChangeStatus    body: { Id, Status }
export const adminChangeStatus = (Id, Status) =>
  api.put('/Admin/ChangeStatus', { Id, Status });

// ─── BOOKINGS ──────────────────────────────────────────────────────────────────
// ⚠️  Update these routes once you share BookingController.js
export const getAllBookings       = ()           => api.get('/Booking/List');
export const getBookingById      = (Id)          => api.get(`/Booking/GetById?Id=${Id}`);
export const updateBookingStatus = (Id, Status)  => api.put('/Booking/ChangeStatus', { Id, Status });

// ─── SERVICEMAN ────────────────────────────────────────────────────────────────
export const getAllServicemen        = ()          => api.get('/Serviceman/List');
export const getPendingServicemen   = ()          => api.get('/Serviceman/PendingList');
export const approveServiceman      = (Id)        => api.put('/Serviceman/Approve', { Id });
export const rejectServiceman       = (Id)        => api.put('/Serviceman/Reject', { Id });
export const changeServicemanStatus = (Id, Status)=> api.put('/Serviceman/ChangeStatus', { Id, Status });

// ─── COMMISSION / SETTLEMENT ───────────────────────────────────────────────────
export const getCommissions    = ()    => api.get('/Commission/List');
export const settleCommission  = (Id)  => api.put('/Commission/Settle', { Id });

// ─── COMPLAINTS ────────────────────────────────────────────────────────────────
export const getAllComplaints       = ()           => api.get('/Complaint/List');
export const updateComplaintStatus = (Id, Status)  => api.put('/Complaint/ChangeStatus', { Id, Status });
export const replyToComplaint      = (Id, Reply)   => api.put('/Complaint/Reply', { Id, Reply });

// ─── REVIEWS / FEEDBACK ────────────────────────────────────────────────────────
export const getAllReviews   = () => api.get('/Review/List');
export const getAllFeedback  = () => api.get('/Feedback/List');
export const replyToReview  = (Id, Reply) => api.put('/Review/Reply', { Id, Reply });

// ─── CUSTOMERS ─────────────────────────────────────────────────────────────────
export const getAllCustomers  = () => api.get('/Customer/List');
export const getCustomerById = (Id) => api.get(`/Customer/GetById?Id=${Id}`);

// ─── SERVICE CATEGORY ──────────────────────────────────────────────────────────
export const getServiceCategories = () => api.get('/ServiceCategory/List');

export default api;
